import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { deleteStaff, getStaff, updateStaff } from "../../api/adminUserApi";
import { getAuth } from "../../utils/auth";

export default function StaffList() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedRole, setSelectedRole] = useState("all");
  const [searchName, setSearchName] = useState("");

  const { role } = getAuth();
  const isAdmin = role === "admin";

  const load = async () => {
    setLoading(true);
    try {
      const res = await getStaff();
      setUsers(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load users");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const toggleActive = async (u) => {
    try {
      await updateStaff(u._id, { isDeleted: !u.isDeleted });
      await load();
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  const hardDelete = async (u) => {
    if (!window.confirm(`Permanently delete ${u.name}?`)) return;

    try {
      await deleteStaff(u._id);
      setUsers(prev => prev.filter(user => user._id !== u._id));
      alert("User deleted permanently");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const filteredUsers = users
    .filter((u) => u.role !== "admin")
    .filter((u) => selectedRole === "all" || u.role === selectedRole)
    .filter((u) => u.name.toLowerCase().includes(searchName.toLowerCase()));

  if (!isAdmin) {
    return (
      <div className="page">
        <div className="pageHead">
          <div>
            <div className="pageTitle">Staff Management</div>
          </div>
        </div>
        <div className="card cardPad" style={{ textAlign: "center", color: "var(--text-light)" }}>Access denied</div>
      </div>
    );
  }

  const getRoleBadgeColor = (role) => {
    const colors = {
      admin: { bg: "#c8e6c9", color: "#1b5e20" },
      manager: { bg: "#bbdefb", color: "#0d47a1" },
      staff: { bg: "#ffe0b2", color: "#e65100" },
      user: { bg: "#f3e5f5", color: "#6a1b9a" },
    };
    return colors[role] || { bg: "#e0e0e0", color: "#424242" };
  };

  return (
    <div className="page" style={{ paddingBottom: "40px" }}>
      {/* Header */}
      <div style={{
        marginBottom: "32px"
      }}>
        <div style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          gap: "24px",
          marginBottom: "24px"
        }}>
          <div>
            <h1 style={{
              fontSize: "32px",
              fontWeight: 700,
              color: "var(--text)",
              margin: "0 0 8px 0",
              letterSpacing: "-0.5px"
            }}>
              Staff Management
            </h1>
            <p style={{
              fontSize: "14px",
              color: "var(--text-muted)",
              margin: 0
            }}>
              Manage team members, roles, and permissions
            </p>
          </div>
          <div style={{ display: "flex", gap: 12 }}>
            <button onClick={load} disabled={loading} style={{
              padding: "10px 16px",
              fontSize: "13px",
              fontWeight: 600,
              border: "1px solid var(--border)",
              backgroundColor: "var(--bg)",
              color: "var(--text)",
              borderRadius: "8px",
              cursor: loading ? "not-allowed" : "pointer",
              transition: "all 0.2s",
              opacity: loading ? 0.6 : 1
            }}
            onMouseEnter={(e) => !loading && (e.currentTarget.style.backgroundColor = "var(--bg-hover)")}
            onMouseLeave={(e) => !loading && (e.currentTarget.style.backgroundColor = "var(--bg)")}
            >
              {loading ? "Loading..." : "↻ Refresh"}
            </button>
            <Link to="/admin/create-staff" style={{ textDecoration: "none" }}>
              <button style={{
                padding: "10px 16px",
                fontSize: "13px",
                fontWeight: 700,
                backgroundColor: "var(--primary)",
                color: "white",
                border: "none",
                borderRadius: "8px",
                cursor: "pointer",
                transition: "all 0.2s",
                letterSpacing: "0.3px"
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.backgroundColor = "var(--primary-hover)";
                e.currentTarget.style.transform = "translateY(-2px)";
                e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.25)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.backgroundColor = "var(--primary)";
                e.currentTarget.style.transform = "translateY(0)";
                e.currentTarget.style.boxShadow = "none";
              }}
              >
                + Add Staff Member
              </button>
            </Link>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div style={{
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        gap: "16px",
        marginBottom: "24px"
      }}>
        {/* Search by Name */}
        <div>
          <label style={{
            display: "block",
            fontSize: "12px",
            fontWeight: 600,
            color: "var(--text)",
            marginBottom: "8px",
            textTransform: "uppercase",
            letterSpacing: "0.3px"
          }}>
            Search by Name
          </label>
          <input
            type="text"
            placeholder="Search staff members..."
            value={searchName}
            onChange={(e) => setSearchName(e.target.value)}
            style={{
              width: "100%",
              padding: "10px 12px",
              fontSize: "13px",
              border: "1px solid var(--border)",
              borderRadius: "8px",
              backgroundColor: "var(--bg)",
              color: "var(--text)",
              boxSizing: "border-box",
              transition: "all 0.2s",
              outline: "none"
            }}
            onFocus={(e) => {
              e.currentTarget.style.borderColor = "var(--primary)";
              e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
            }}
            onBlur={(e) => {
              e.currentTarget.style.borderColor = "var(--border)";
              e.currentTarget.style.boxShadow = "none";
            }}
          />
        </div>

        {/* Filter by Role */}
        <div>
          <label style={{
            display: "block",
            fontSize: "12px",
            fontWeight: 600,
            color: "var(--text)",
            marginBottom: "8px",
            textTransform: "uppercase",
            letterSpacing: "0.3px"
          }}>
            Filter by Role
          </label>
          <select
            value={selectedRole}
            onChange={(e) => setSelectedRole(e.target.value)}
            style={{
              width: "100%",
              padding: "10px 12px",
              fontSize: "13px",
              border: "1px solid var(--border)",
              borderRadius: "8px",
              backgroundColor: "var(--bg)",
              color: "var(--text)",
              boxSizing: "border-box",
              cursor: "pointer",
              transition: "all 0.2s",
              outline: "none"
            }}
            onFocus={(e) => {
              e.currentTarget.style.borderColor = "var(--primary)";
              e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
            }}
            onBlur={(e) => {
              e.currentTarget.style.borderColor = "var(--border)";
              e.currentTarget.style.boxShadow = "none";
            }}
          >
            <option value="all">All Roles</option>
            <option value="manager">Manager</option>
            <option value="staff">Staff</option>
            <option value="user">User</option>
          </select>
        </div>
      </div>

      {/* Staff Table */}
      <div style={{
        backgroundColor: "var(--bg-card)",
        borderRadius: "12px",
        border: "1px solid var(--border)",
        boxShadow: "0 4px 12px rgba(0,0,0,0.05)",
        overflow: "hidden"
      }}>
        {/* Table Header with Stats */}
        <div style={{
          padding: "20px 24px",
          borderBottom: "1px solid var(--border)",
          backgroundColor: "linear-gradient(135deg, rgba(76, 175, 80, 0.03) 0%, rgba(26, 71, 42, 0.02) 100%)"
        }}>
          <div style={{
            fontSize: "13px",
            color: "var(--text-muted)",
            fontWeight: 500
          }}>
            Showing <strong style={{ color: "var(--text)" }}>{filteredUsers.length}</strong> of <strong style={{ color: "var(--text)" }}>{users.filter((u) => u.role !== "admin").length}</strong> staff members
          </div>
        </div>

        {/* Scrollable Table */}
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ borderBottom: "2px solid var(--border)", backgroundColor: "var(--bg)" }}>
                <th style={{ padding: "14px 24px", fontWeight: 700, color: "var(--text)", fontSize: "12px", textAlign: "left", textTransform: "uppercase", letterSpacing: "0.3px" }}>Name</th>
                <th style={{ padding: "14px 24px", fontWeight: 700, color: "var(--text)", fontSize: "12px", textAlign: "left", textTransform: "uppercase", letterSpacing: "0.3px" }}>Email</th>
                <th style={{ padding: "14px 24px", fontWeight: 700, color: "var(--text)", fontSize: "12px", textAlign: "left", textTransform: "uppercase", letterSpacing: "0.3px" }}>Role</th>
                <th style={{ padding: "14px 24px", fontWeight: 700, color: "var(--text)", fontSize: "12px", textAlign: "left", textTransform: "uppercase", letterSpacing: "0.3px" }}>Status</th>
                <th style={{ padding: "14px 24px", fontWeight: 700, color: "var(--text)", fontSize: "12px", textAlign: "left", textTransform: "uppercase", letterSpacing: "0.3px" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsers.map((u) => {
                const roleBadge = getRoleBadgeColor(u.role);
                return (
                  <tr 
                    key={u._id} 
                    style={{ 
                      borderBottom: "1px solid var(--border)",
                      transition: "background-color 0.2s",
                      backgroundColor: "var(--bg-card)"
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.backgroundColor = "var(--bg-hover)"}
                    onMouseLeave={(e) => e.currentTarget.style.backgroundColor = "var(--bg-card)"}
                  >
                    <td style={{ padding: "16px 24px", color: "var(--text)", fontSize: "14px", fontWeight: 500 }}>{u.name}</td>
                    <td style={{ padding: "16px 24px", color: "var(--text-muted)", fontSize: "13px" }}>{u.email}</td>
                    <td style={{ padding: "16px 24px" }}>
                      <span style={{
                        display: "inline-block",
                        backgroundColor: roleBadge.bg,
                        color: roleBadge.color,
                        padding: "6px 12px",
                        borderRadius: "6px",
                        fontSize: "12px",
                        fontWeight: 600,
                        textTransform: "capitalize",
                        letterSpacing: "0.2px"
                      }}>
                        {u.role}
                      </span>
                    </td>
                    <td style={{ padding: "16px 24px" }}>
                      <div style={{
                        display: "inline-flex",
                        alignItems: "center",
                        gap: "6px",
                        padding: "4px 10px",
                        borderRadius: "6px",
                        backgroundColor: u.isDeleted ? "#ffebee" : "#e8f5e9",
                        fontSize: "12px",
                        fontWeight: 600,
                        color: u.isDeleted ? "#c62828" : "#2e7d32"
                      }}>
                        <span style={{ fontSize: "10px" }}>{u.isDeleted ? "●" : "●"}</span>
                        {u.isDeleted ? "Deactivated" : "Active"}
                      </div>
                    </td>
                    <td style={{ padding: "16px 24px" }}>
                      <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                        <Link to={`/admin/staff/edit/${u._id}`} style={{ textDecoration: "none" }}>
                          <button style={{
                            padding: "6px 12px",
                            fontSize: "12px",
                            fontWeight: 600,
                            border: "1px solid var(--border)",
                            backgroundColor: "var(--bg)",
                            color: "var(--text)",
                            borderRadius: "6px",
                            cursor: "pointer",
                            transition: "all 0.2s",
                            letterSpacing: "0.2px"
                          }}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.borderColor = "var(--primary)";
                            e.currentTarget.style.color = "var(--primary)";
                            e.currentTarget.style.boxShadow = "0 0 0 2px var(--primary-soft)";
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.borderColor = "var(--border)";
                            e.currentTarget.style.color = "var(--text)";
                            e.currentTarget.style.boxShadow = "none";
                          }}
                          >
                            Edit
                          </button>
                        </Link>
                        <button 
                          style={{
                            padding: "6px 12px",
                            fontSize: "12px",
                            fontWeight: 600,
                            border: "1px solid var(--border)",
                            backgroundColor: "var(--bg)",
                            color: u.isDeleted ? "#4caf50" : "#ff9800",
                            borderRadius: "6px",
                            cursor: "pointer",
                            transition: "all 0.2s",
                            letterSpacing: "0.2px"
                          }}
                          onClick={() => toggleActive(u)}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.borderColor = u.isDeleted ? "#4caf50" : "#ff9800";
                            e.currentTarget.style.backgroundColor = u.isDeleted ? "#e8f5e9" : "#fff3e0";
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.borderColor = "var(--border)";
                            e.currentTarget.style.backgroundColor = "var(--bg)";
                          }}
                        >
                          {u.isDeleted ? "Activate" : "Deactivate"}
                        </button>
                        <button 
                          style={{
                            padding: "6px 12px",
                            fontSize: "12px",
                            fontWeight: 600,
                            border: "1px solid #ffcdd2",
                            backgroundColor: "#ffebee",
                            color: "#c62828",
                            borderRadius: "6px",
                            cursor: "pointer",
                            transition: "all 0.2s",
                            letterSpacing: "0.2px"
                          }}
                          onClick={() => hardDelete(u)}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.backgroundColor = "#ffcdd2";
                            e.currentTarget.style.transform = "scale(1.02)";
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.backgroundColor = "#ffebee";
                            e.currentTarget.style.transform = "scale(1)";
                          }}
                        >
                          Delete
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}

              {filteredUsers.length === 0 && !loading && (
                <tr>
                  <td colSpan="5" style={{ padding: "48px 24px", textAlign: "center" }}>
                    <div style={{ color: "var(--text-muted)" }}>
                      <p style={{ fontSize: "16px", fontWeight: 500, margin: "0 0 8px 0" }}>No staff members found</p>
                      <p style={{ fontSize: "13px", margin: 0 }}>
                        {searchName || selectedRole !== "all" ? "Try adjusting your filters" : "Create your first staff member"}
                      </p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <style>{`
        @media (max-width: 768px) {
          div[style*="gridTemplateColumns"] {
            grid-template-columns: 1fr !important;
          }
          table {
            font-size: 12px;
          }
          table td {
            padding: 12px 16px !important;
          }
        }
      `}</style>
    </div>
  );
}
